private void checkReminders(JSONObject result, String apname, String path, int sheetIndex, int designerQuerySeq) throws Exception {
	NUIForm form = AppManager.getFormPage(apname, path, sheetIndex);
    if(form == null) throw new Exception("Form " + apname + path + "/" + sheetIndex + " not exists.");
    
    JSONArray rmdNames = new JSONArray();
    form.getReminders().forEach(rmd -> {
        if(rmd.getViewId() != designerQuerySeq) return;
        rmdNames.put(Encoder.encjs(rmd.getName()));
    });
    if(rmdNames.length() > 0) {
    	result.put("reminder", rmdNames);
    }
}

private void checkScheduleReports(JSONObject result, String apname, String path, int sheetIndex, int designerQuerySeq, RagicBundle bundle) throws Exception {
	RagicAccountJobs accountJobs = RagicAccountJobs.getInstance();
	RagicAccountJobSchedule schedule = accountJobs.getJobSchedule(apname, Const.JOB_EXPORT_VIEW_EMAIL);
    if(schedule == null) return;
    JSONArray reportNames = new JSONArray();
    for(Map.Entry<String, String> e: schedule.getParamMap().entrySet()) {
        try {
        	String scheduleParamKey = e.getKey();
            String paramJSONStr = e.getValue();
            JSONObject paramJSON = new JSONObject(paramJSONStr);
            
            String path_report = paramJSON.getString("path");
            if(!path_report.equals(path)) continue;
            
            String sheet_report = paramJSON.getString("sheet");
            int sheetIndex_report = Encoder.parseInt(sheet_report.substring(0, sheet_report.indexOf("_")), -1);
            if(sheetIndex_report == -1 || sheetIndex_report != sheetIndex) continue;
            
            int reportId = paramJSON.getInt("reportId");
            if(reportId != designerQuerySeq) continue;
            
            String reportName = paramJSON.optString("name", bundle.getString("untitledReport"));
            reportNames.put(reportName);
        } catch(Exception ignored) {
        }
    }
    if(reportNames.length() > 0) {
    	result.put("exportReport", reportNames);
    }
}

